export async function POST(req: NextRequest) {
  const secret = req.headers.get('x-admin-secret')
  if (secret !== process.env.ADMIN_SECRET) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }
  const sb = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL || '',
    process.env.SUPABASE_SERVICE_ROLE_KEY || '',
    { auth: { autoRefreshToken: false, persistSession: false } }
  )
  let inserted = 0
  const errors: string[] = []
  for (let i = 0; i < FIRMA_DATA.length; i += 50) {
    const chunk = FIRMA_DATA.slice(i, i + 50)
    const { error, count } = await sb.from('firmalar').insert(chunk, { count: 'exact' })
    if (error) errors.push(`chunk${i}: ${error.message}`)
    else inserted += count || chunk.length
  }
  return NextResponse.json({ inserted, errors, total: FIRMA_DATA.length })
}
